import React from 'react';
import { TodoList } from './TodoList';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '32rem', margin: '0 auto' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Todo List</h1>
      <TodoList />
    </div>
  );
}

import React, { useReducer, useMemo, useState } from 'react';
import './styles.css';

// --- Types ---
export interface Todo {
  id: number;
  text: string;
  completed: boolean;
}

export type FilterType = 'all' | 'active' | 'completed';

export interface TodoState {
  todos: Todo[];
  filter: FilterType;
}

type TodoAction =
  | { type: 'ADD_TODO'; text: string }
  | { type: 'TOGGLE_TODO'; id: number }
  | { type: 'REMOVE_TODO'; id: number }
  | { type: 'SET_FILTER'; filter: FilterType };

let nextId = 1;

// --- Reducer ---
export function todoReducer(state: TodoState, action: TodoAction): TodoState {
  switch (action.type) {
    case 'ADD_TODO':
      // TODO: Add new todo to the list
      return state;
    case 'TOGGLE_TODO':
      // TODO: Toggle completed for the matching id
      return state;
    case 'REMOVE_TODO':
      // TODO: Remove todo by id
      return state;
    case 'SET_FILTER':
      // TODO: Update the filter
      return state;
    default:
      return state;
  }
}

// --- Component ---
export const TodoList: React.FC = () => {
  const [state, dispatch] = useReducer(todoReducer, { todos: [], filter: 'all' });
  const [input, setInput] = useState('');

  const filteredTodos = useMemo(() => {
    switch (state.filter) {
      case 'active':
        return state.todos.filter(t => !t.completed);
      case 'completed':
        return state.todos.filter(t => t.completed);
      default:
        return state.todos;
    }
  }, [state.todos, state.filter]);

  const activeCount = state.todos.filter(t => !t.completed).length;

  const handleAdd = () => {
    if (input.trim()) {
      dispatch({ type: 'ADD_TODO', text: input.trim() });
      setInput('');
    }
  };

  return (
    <div>
      <div className="todo-input-row">
        <input
          data-testid="todo-input"
          className="todo-input"
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && handleAdd()}
          placeholder="What needs to be done?"
        />
        <button data-testid="add-btn" className="todo-add-btn" onClick={handleAdd}>Add</button>
      </div>
      <div className="todo-filters">
        {(['all', 'active', 'completed'] as FilterType[]).map(f => (
          <button
            key={f}
            data-testid={`filter-${f}`}
            className={`todo-filter${state.filter === f ? ' todo-filter--active' : ''}`}
            onClick={() => dispatch({ type: 'SET_FILTER', filter: f })}
          >
            {f.charAt(0).toUpperCase() + f.slice(1)}
          </button>
        ))}
      </div>
      <ul className="todo-list">
        {filteredTodos.map(todo => (
          <li key={todo.id} data-testid={`todo-${todo.id}`} className={`todo-item${todo.completed ? ' todo-item--done' : ''}`}>
            <input
              type="checkbox"
              data-testid={`toggle-${todo.id}`}
              checked={todo.completed}
              onChange={() => dispatch({ type: 'TOGGLE_TODO', id: todo.id })}
            />
            <span>{todo.text}</span>
            <button data-testid={`remove-${todo.id}`} className="todo-remove" onClick={() => dispatch({ type: 'REMOVE_TODO', id: todo.id })}>✕</button>
          </li>
        ))}
      </ul>
      <p className="todo-count" data-testid="active-count">{activeCount} item{activeCount !== 1 ? 's' : ''} left</p>
    </div>
  );
};

.todo-input-row {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.todo-input {
  flex: 1;
  padding: 0.625rem 0.875rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.9375rem;
  outline: none;
}

.todo-input:focus {
  border-color: #3b82f6;
}

.todo-add-btn {
  padding: 0.625rem 1rem;
  background: #3b82f6;
  color: white;
  border: none;
  border-radius: 0.375rem;
  cursor: pointer;
  font-size: 0.875rem;
}

.todo-filters {
  display: flex;
  gap: 0.25rem;
  margin-bottom: 1rem;
}

.todo-filter {
  padding: 0.375rem 0.75rem;
  border: 1px solid #d1d5db;
  background: #f9fafb;
  border-radius: 0.25rem;
  cursor: pointer;
  font-size: 0.8125rem;
}

.todo-filter--active {
  background: #3b82f6;
  color: white;
  border-color: #3b82f6;
}

.todo-list {
  list-style: none;
  padding: 0;
  margin: 0;
}

.todo-item {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.625rem 0;
  border-bottom: 1px solid #f3f4f6;
}

.todo-item--done span {
  text-decoration: line-through;
  color: #9ca3af;
}

.todo-remove {
  margin-left: auto;
  background: none;
  border: none;
  color: #ef4444;
  cursor: pointer;
  font-size: 0.875rem;
}

.todo-count {
  margin-top: 0.75rem;
  font-size: 0.8125rem;
  color: #6b7280;
}

