import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { todoReducer } from './TodoList';

describe('todoReducer', () => {
  const initialState = { todos: [], filter: 'all' as const };

  it('adds a new todo', () => {
    const result = todoReducer(initialState, { type: 'ADD_TODO', text: 'Buy milk' });
    expect(result.todos).toHaveLength(1);
    expect(result.todos[0].text).toBe('Buy milk');
    expect(result.todos[0].completed).toBe(false);
  });

  it('toggles a todo', () => {
    const state = { todos: [{ id: 1, text: 'Test', completed: false }], filter: 'all' as const };
    const result = todoReducer(state, { type: 'TOGGLE_TODO', id: 1 });
    expect(result.todos[0].completed).toBe(true);
  });

  it('toggles back to incomplete', () => {
    const state = { todos: [{ id: 1, text: 'Test', completed: true }], filter: 'all' as const };
    const result = todoReducer(state, { type: 'TOGGLE_TODO', id: 1 });
    expect(result.todos[0].completed).toBe(false);
  });

  it('removes a todo', () => {
    const state = {
      todos: [{ id: 1, text: 'A', completed: false }, { id: 2, text: 'B', completed: false }],
      filter: 'all' as const,
    };
    const result = todoReducer(state, { type: 'REMOVE_TODO', id: 1 });
    expect(result.todos).toHaveLength(1);
    expect(result.todos[0].id).toBe(2);
  });

  it('sets filter', () => {
    const result = todoReducer(initialState, { type: 'SET_FILTER', filter: 'active' });
    expect(result.filter).toBe('active');
  });

  it('does not mutate the original state', () => {
    const state = { todos: [{ id: 1, text: 'A', completed: false }], filter: 'all' as const };
    const frozen = Object.freeze({ ...state, todos: Object.freeze(state.todos.map(t => Object.freeze(t))) });
    expect(() => todoReducer(frozen as any, { type: 'TOGGLE_TODO', id: 1 })).not.toThrow();
  });

  it('preserves filter when modifying todos', () => {
    const state = { todos: [], filter: 'completed' as const };
    const result = todoReducer(state, { type: 'ADD_TODO', text: 'New' });
    expect(result.filter).toBe('completed');
  });
});

